const DEFAULT_MODEL="anthropic/claude-3-haiku";async function loadSettings(){const e=await chrome.storage.sync.get(["apiKey","model"]);document.getElementById("apiKey").value=e.apiKey||"",document.getElementById("model").value=e.model||DEFAULT_MODEL}async function saveSettings(e){e.preventDefault();const t=document.getElementById("apiKey").value.trim(),s=document.getElementById("model").value;!t||t.startsWith("sk-or-")?(await chrome.storage.sync.set({apiKey:t,model:s}),showStatus("Settings saved successfully!","success")):showStatus("Please enter a valid OpenRouter API key (starts with sk-or-)","error")}async function resetSettings(){confirm("Reset all settings to defaults?")&&(await chrome.storage.sync.clear(),await loadSettings(),showStatus("Settings reset to defaults","success"))}function showStatus(e,t){const s=document.getElementById("statusMessage");s.textContent=e,s.className=`status-message ${t} show`,setTimeout(()=>{s.classList.remove("show")},3e3)}document.getElementById("settingsForm").addEventListener("submit",saveSettings),document.getElementById("resetBtn").addEventListener("click",resetSettings),loadSettings();